def parse_or_quarantine(row):
    try:
        return "ok", int(row)
    except ValueError:
        return "quarantine", row
print(parse_or_quarantine("10"), parse_or_quarantine("x"))

def mask_email(e):
    if "@" not in e:
        return "***"
    local, domain = e.split("@", 1)
    return (local[:1] + "***@" + domain) if local else "***@" + domain
print(mask_email("ana@ejemplo.pe"))

def mask_phone(p):
    digits = "".join(c for c in p if c.isdigit())
    if len(digits) < 4:
        return "***"
    return "*" * (len(digits) - 4) + digits[-4:]
print(mask_phone("999000111"))

def fetch(retry=0):
    if retry < 2:
        raise TimeoutError("temp")
    return "ok"
attempt = 0
while True:
    try:
        print(fetch(attempt))
        break
    except TimeoutError:
        attempt += 1
        if attempt > 3:
            raise

def classify_error(e):
    if isinstance(e, TimeoutError):
        return "retryable"
    if isinstance(e, ValueError):
        return "data"
    return "other"
print(classify_error(TimeoutError()), classify_error(ValueError("x")))

import time
def backoff(i):
    return min(2 ** i, 8)
print([backoff(i) for i in range(4)])

def minimal_repro(rows):
    for r in rows:
        try:
            int(r)
        except ValueError:
            return r
    return None
print(minimal_repro(["1", "2", "x", "4"]))

def assert_repro(fn, sample):
    try:
        fn(sample)
        return "no_fail"
    except Exception as e:
        return type(e).__name__
print(assert_repro(lambda s: int(s), "x"))

